/**
 * @generated by @flusk/cli
 * Training status subcommand
 */
import chalk from 'chalk';
import { createSqliteStorage } from '@flusk/resources';
import { getCollectionStats } from '@flusk/business-logic';

// --- BEGIN CUSTOM ---
interface StatusOpts {
  tenant?: string;
}

export function trainingStatusAction(opts: StatusOpts): void {
  const storage = createSqliteStorage();
  const tenantId = opts.tenant ?? '';
  const total = tenantId
    ? storage.trainingPairs.countByTenant(tenantId) as number
    : storage.trainingPairs.list(1, 0).length > 0
      ? storage.trainingPairs.countByTenant('') as number
      : 0;

  const byModel = storage.trainingPairs.countByModelGrouped() as Array<{
    model: string; count: number;
  }>;
  const byCluster = storage.trainingPairs.countByClusterGrouped() as Array<{
    cluster: string; count: number;
  }>;

  const stats = getCollectionStats(total, byModel, byCluster);

  console.log(chalk.bold('\n📊 Training Data Collection Status\n'));
  console.log(`  Total pairs: ${chalk.cyan(String(stats.totalPairs))}`);
  console.log(`  Ready clusters: ${chalk.green(String(stats.readyForTraining))}`);

  if (byModel.length > 0) {
    console.log(chalk.bold('\n  By Model:'));
    for (const m of byModel) {
      console.log(`    ${m.model}: ${chalk.cyan(String(m.count))}`);
    }
  }

  if (byCluster.length > 0) {
    console.log(chalk.bold('\n  By Cluster:'));
    for (const c of byCluster) {
      console.log(`    ${c.cluster}: ${chalk.cyan(String(c.count))}`);
    }
  }
  console.log();
}
// --- END CUSTOM ---
